(* ============================================================ *)
(* 섹션: 메인 (PAGE 82)                                         *)
(* ============================================================ *)

(* 래더 Line 0 - 코어 초기 SOL 출력 정의 (코일 선언 래더) *)
(* _M06312, _M06314, _M06316, _M06310, _M06318, _M0631A, _M0631C *)
(* _M0631E, _M06320, _M06913, _M06000, _M06319 → 후속 로직에서 제어 *)

(* 래더 Line 14 - 반자동 모드 시작 조건 *)
(* 자동모드(_M00010) AND 코어알람없음(NOT _M00176) AND 도어알람없음(NOT _M00840) *)
(* AND 코어유닛상태(_M06001) AND 사이클스톱없음(NOT _M00075) AND 반자동비트(_M06004) *)

(* 래더 Line 21 - 반자동 지연 타이머 *)
TON_T0600(IN := _M06004, PT := T#3000ms);

(* 래더 Line 24 - 반자동 진입 추가 조건 체크 *)
(* 자동모드 AND 코어알람없음 AND 알람TOTAL없음 AND _D00620<>0 AND M00075없음 *)

(* 래더 Line 31 - 반자동 SET: 수동+반자동비트+T0600만료 → _K00260 상승에지 *)
R_TRIG_K00260(CLK := _K00260);
IF _M00011 AND _M06004 AND TON_T0600.Q AND R_TRIG_K00260.Q THEN
    _M06002 := TRUE;  (* 코어 자동 운전 SET *)
    _M00803 := TRUE;  (* 인덱스 서보 알람 SET *)
END_IF;

(* 래더 Line 37 - 자동모드+코어알람 조건 *)
IF _M00010 AND _M00176 THEN
    (* 알람 상태 처리 - 후속 래더에서 제어 *)
END_IF;

(* 래더 Line 41 - 반자동 해제 타이머 *)
TON_T0601(IN := _M06002, PT := T#2000ms);

(* 래더 Line 44 - 반자동 RST: T0601만료 AND 반자동비트 → _K00260 상승에지 *)
R_TRIG_K00260(CLK := _K00260);
IF TON_T0601.Q AND _M06004 AND _M00011 AND R_TRIG_K00260.Q THEN
    _M06002 := FALSE; (* 코어 자동 운전 RST *)
END_IF;

(* 래더 Line 51 - 초기위치 동작 조건: _M06004 OR _M06002 → _M06005 *)
_M06005 := _M06004 OR _M06002;

(* 래더 Line 54 - 초기위치 이동 시작 조건 에지 *)
R_TRIG_M06005(CLK := _M06005);
R_TRIG_M00021(CLK := _M00021);

IF _M06005 AND _M00021 AND _M00010 THEN
    R_TRIG_M00021(CLK := _M00021);
    IF R_TRIG_M00021.Q THEN
        (* 초기위치 완료 상승에지 처리 *)
    END_IF;
END_IF;

(* 래더 Line 71 - 반자동 완료 → 코어 반자동 SET *)
(* 수동 AND 코어유닛상태 → _K00260 P(상승에지) *)
R_TRIG_K00260(CLK := _K00260);
IF _M00011 AND _M06000 AND R_TRIG_K00260.Q THEN
    _M06004 := TRUE; (* 코어 반자동 SET *)
    _D00018 := 1;    (* MOV 1 → _D00018: 코어 스테이션 번호 *)
END_IF;

(* 래더 Line 78 - 반자동 완료 후 리셋 조건 *)
(* _M06004 AND _M06218 AND _M01106 AND _M0631C AND _M06320 → _K00261 P *)
R_TRIG_K00261(CLK := _K00261);
IF _M06004 AND _M06218 AND _M01106 AND _M0631C AND _M06320 THEN
    _M06004 := FALSE;  (* 코어 반자동 RST *)
    _M06002 := FALSE;  (* 코어 자동 운전 RST *)
    IF R_TRIG_K00261.Q THEN
        _D00018 := 0;  (* MOVP 0 → _D00018 *)
    END_IF;
    _M00304 := TRUE;   (* 자동 운전 상태 SET *)
END_IF;

(* 래더 Line 93 - 초기위치 완료: 수동 AND 코어유닛상태 → _K00261 P *)
R_TRIG_K00261(CLK := _K00261);
IF _M00011 AND _M06000 AND R_TRIG_K00261.Q THEN
    _M06005 := TRUE;   (* 코어 초기위치 SET *)
    R_TRIG_M00021(CLK := _M00021);
    (* _M00021 상승에지 처리 *)
END_IF;

(* 래더 Line 101 - 초기위치 완료 처리 *)
IF _M06000 AND _M06010 THEN
    _M06005 := FALSE;  (* 코어 초기위치 RST *)
END_IF;
F_TRIG_F0009A(CLK := _OFF);
IF _M00011 AND NOT _M00030 AND _M00304 AND F_TRIG_F0009A.Q THEN
    (* _OFF 하강에지 처리 *)
END_IF;

(* ============================================================ *)
(* 섹션: 운전 준비 - _D00600 CASE문 (PAGE 83)                   *)
(* ============================================================ *)

(* 래더 Line 110 - 운전준비 스텝 DECO: DECO _D00600 → M0601x (4비트) *)
(* XEC: 등가 비교 방식으로 변환 *)
_M06010 := (_D00600 = 0);
_M06011 := (_D00600 = 1);
_M06012 := (_D00600 = 2);
_M06013 := (_D00600 = 3);
_M06014 := (_D00600 = 4);
_M06015 := (_D00600 = 5);
_M06016 := (_D00600 = 6);
_M06017 := (_D00600 = 7);
_M06018 := (_D00600 = 8);
_M06019 := (_D00600 = 9);

(* 래더 Line 115 - 운전준비 스텝 리셋: 자동모드 AND EMO → MOV 0 _D00600 *)
IF _M00010 AND _M00030 THEN
    _D00600 := 0;
END_IF;

(* 래더 Line 126 - 수동 AND NOT 초기위치동작: _OFF 하강에지 처리 *)
F_TRIG_F0009A(CLK := _OFF);
IF _M00011 AND NOT _M06005 AND F_TRIG_F0009A.Q THEN
    (* 수동모드 초기화 트리거 *)
END_IF;

CASE _D00600 OF
    0: (* 래더 Line 126 - 스텝0: 대기 → 초기위치 상승에지 시 스텝1 *)
        R_TRIG_M06005(CLK := _M06005);
        IF _M00011 AND _M06010 AND R_TRIG_M06005.Q THEN
            _D00600 := 1;
        END_IF;

    1: (* 래더 Line 132 - 스텝1: 코어 높이검사 후진(_M0631E), _T0611 대기 *)
        _M0631E := TRUE; (* 코어 높이검사 전진/후진 SOL: 후진 *)
        TON_T0611(IN := _M06011, PT := T#5000ms);
        IF TON_T0611.Q THEN
            _D00600 := 2;
        END_IF;

    2: (* 래더 Line 141 - 스텝2: 코어 2차이송 클램프(_M0631A), _T0612 대기 *)
        _M0631A := TRUE; (* 코어 2차이송 클램프 SOL *)
        TON_T0612(IN := _M06012, PT := T#5000ms);
        IF TON_T0612.Q THEN
            _D00600 := 3;
        END_IF;

    3: (* 래더 Line 150 - 스텝3: 코어 2차이송 회전복귀(_M06318), _T0613 대기 *)
        _M06318 := TRUE; (* 코어 2차이송 회전복귀 SOL *)
        TON_T0613(IN := _M06013, PT := T#5000ms);
        IF TON_T0613.Q THEN
            _D00600 := 4;
        END_IF;

    4: (* 래더 Line 161 - 스텝4: 코어 2차이송 후진(_M06314), _T0614 대기 *)
        _M06314 := TRUE; (* 코어 2차이송 후진 SOL *)
        TON_T0614(IN := _M06014, PT := T#5000ms);
        IF TON_T0614.Q THEN
            _D00600 := 5;
        END_IF;

    5: (* 래더 Line 170 - 스텝5: 코어 1차이송 전진/후진(_M06312), _T0615 대기 *)
        _M06312 := TRUE; (* 코어 1차이송 전진/후진 SOL *)
        TON_T0615(IN := _M06015, PT := T#5000ms);
        IF TON_T0615.Q THEN
            _D00600 := 6;
        END_IF;

    6: (* 래더 Line 179 - 스텝6: 코어 2차이송 상승/하강(_M06316), _T0616 대기 *)
        _M06316 := TRUE; (* 코어 2차이송 상승/하강 SOL *)
        TON_T0616(IN := _M06016, PT := T#5000ms);
        IF TON_T0616.Q THEN
            _D00600 := 7;
        END_IF;

    7: (* 래더 Line 188 - 스텝7: 코어 상부(_M0631C)+하부(_M06320), _T0617 대기 *)
        _M0631C := TRUE; (* 코어 상부 상승/하강 SOL *)
        _M06320 := TRUE; (* 코어 하부 하강 SOL *)
        TON_T0617(IN := _M06017, PT := T#5000ms);
        IF TON_T0617.Q THEN
            _D00600 := 8;
        END_IF;

    8: (* 래더 Line 198 - 스텝8: 코어 제품차단(_M06310), _T0618 대기 *)
        _M06310 := TRUE; (* 코어 제품차단 SOL *)
        TON_T0618(IN := _M06018, PT := T#5000ms);
        IF TON_T0618.Q THEN
            _D00600 := 9;
        END_IF;

    9: (* 래더 Line 207 - 스텝9: _M06913 ON, _T0619 대기 → 스텝0(완료) *)
        _M06913 := TRUE; (* 운전준비 완료 출력 *)
        TON_T0619(IN := _M06019, PT := T#5000ms);
        IF TON_T0619.Q THEN
            _D00600 := 0; (* 운전준비 완료, 스텝 리셋 *)
        END_IF;
END_CASE;

(* ============================================================ *)
(* 섹션: AUTO STEP 1 - _D00620 자동 시퀀스 (PAGE 83-86)          *)
(* ============================================================ *)

(* 래더 Line 217 - 자동스텝 DECO: DECO _D00620 → M0620x (6비트) *)
(* _M00304 조건부 실행 *)
IF _M00304 THEN
    _M06200 := (_D00620 = 0);
    _M06201 := (_D00620 = 1);
    _M06202 := (_D00620 = 2);
    _M06203 := (_D00620 = 3);
    _M06204 := (_D00620 = 4);
