    _M0620D := (_D00620 = 13);
    _M0620E := (_D00620 = 14);
    _M0620F := (_D00620 = 15);
    _M06210 := (_D00620 = 16);
    _M06211 := (_D00620 = 17);
    _M06212 := (_D00620 = 18);
    _M06213 := (_D00620 = 19);
    _M06214 := (_D00620 = 20);
    _M06215 := (_D00620 = 21);
    _M06216 := (_D00620 = 22);
    _M06217 := (_D00620 = 23);
    _M06218 := (_D00620 = 24);
END_IF;

(* 래더 Line 223 - 자동 스텝 리셋: EMO OR 정지스위치 → MOV 0 _D00620 *)
IF _M00030 OR _T0013 THEN
    _D00620 := 0;
END_IF;

(* 래더 Line 223 - 수동+사이클스톱+반자동+초기위치 P에지 체크 *)
R_TRIG_M00021(CLK := _M00021);
IF _M00011 AND _M00075 AND _M06004 AND R_TRIG_M00021.Q THEN
    (* 수동모드 사이클스톱 시 초기위치 상승에지 처리 *)
END_IF;

(* 래더 Line 223 - 코어알람 AND NOT 반자동 *)
IF _M00176 AND NOT _M06004 THEN
    (* 알람 상태 처리 *)
END_IF;

CASE _D00620 OF
    0: (* 래더 Line 237 - 스텝0: 대기/시작 조건 판단 (PAGE 84) *)
        (* 자동운전중 AND 코어상태 AND 코어작업시작조건 AND NOT 정지 → 스텝1 *)
        IF _M06002 AND _M06001 AND _M06200 AND NOT _M00012 THEN
            _D00620 := 1;
        END_IF;
        (* _M06251(특수플래그) AND _M06318(회전복귀상태) → 스텝7 점프 *)
        IF _M06251 AND _M06318 THEN
            _D00620 := 7;
        END_IF;
        (* _M06319(회전완료) → 스텝7 점프 *)
        IF _M06319 THEN
            _D00620 := 7;
        END_IF;
        (* _M06251(특수플래그만) → 스텝19 점프 *)
        IF _M06251 AND NOT _M06318 AND NOT _M06319 THEN
            _D00620 := 19;
        END_IF;

    1: (* 래더 Line 255 - 스텝1: 대기 T#300ms *)
        TON_T0621(IN := _M06002 AND _M06201, PT := T#3000ms);
        IF TON_T0621.Q THEN
            _D00620 := 2;
        END_IF;

    2: (* 래더 Line 264 - 스텝2: 코어 자재확인 트리거, T#500ms *)
        _M06300 := TRUE; (* 코어 자재확인 트리거 *)
        TON_T0622(IN := _M06002 AND _M06202, PT := T#5000ms);
        IF TON_T0622.Q THEN
            _D00620 := 3;
        END_IF;
        (* _M01116(자재없음) AND _M01106(작업완료): 자재없음 처리 *)
        (* _M01987 AND _M01115: 드라이런 처리 *)

    3: (* 래더 Line 282 - 스텝3: 코어 하부(_M0631D+_M06321) ON, T#500ms *)
        _M0631D := TRUE; (* 코어 하부 상승/하강 SOL *)
