        TON_T0623(IN := _M06002 AND _M06203, PT := T#5000ms);
        IF TON_T0623.Q THEN
            _D00620 := 4;
        END_IF;

    4: (* 래더 Line 297 - 스텝4: 코어 2차이송 전진(_M06311) ON, T#500ms *)
        _M06311 := TRUE; (* 코어 2차이송 전진 SOL *)
        TON_T0624(IN := _M06002 AND _M06204, PT := T#5000ms);
        IF TON_T0624.Q THEN
            _D00620 := 5;
        END_IF;

    5: (* 래더 Line 307 - 스텝5: 코어 2차이송 전진(_M06315) ON, T#200ms *)
        _M06315 := TRUE; (* 코어 2차이송 전진 SOL(보조) *)
        TON_T0625(IN := _M06002 AND _M06205, PT := T#2000ms);
        IF TON_T0625.Q THEN
            _D00620 := 6;
        END_IF;

    6: (* 래더 Line 317 - 스텝6: 코어 2차이송 회전(_M06319) ON, T#200ms *)
        _M06319 := TRUE; (* 코어 2차이송 회전 SOL *)
        TON_T0626(IN := _M06002 AND _M06206, PT := T#2000ms);
        IF TON_T0626.Q THEN
