        END_IF;

    7: (* 래더 Line 327 - 스텝7: 코어 2차이송 후진(_M06314) ON, 자재확인, T#200ms *)
        _M06314 := TRUE; (* 코어 2차이송 후진 SOL *)
        TON_T0627(IN := _M06002 AND _M06207, PT := T#2000ms);
        IF TON_T0627.Q THEN
            _D00620 := 8;
        END_IF;
        (* 자재없음(_M01116) AND 작업완료(_M01106) AND 인덱스=1 *)
        IF _M01116 AND _M01106 AND (_D00018 = 1) THEN
            (* 자재없음 처리 *)
        END_IF;
        (* 드라이런(_M01987) AND 인덱스=3 → 코어 작업완료 SET *)
        IF _M01987 AND (_D00018 = 3) THEN
            _M01106 := TRUE; (* 코어 작업완료 SET *)
        END_IF;

    8: (* 래더 Line 349 - 스텝8: 코어 하부(_M06321+_M0631D) ON, T#200ms *)
        _M06321 := TRUE;
        _M0631D := TRUE; (* 코어 하부 상승/하강 SOL *)
        TON_T0628(IN := _M06002 AND _M06208, PT := T#2000ms);
        IF TON_T0628.Q THEN
            _D00620 := 9;
        END_IF;

    9: (* 래더 Line 360 - 스텝9: 코어 회전복귀보조(_M06317)+제품차단(_M06310), T#200ms *)
        _M06317 := TRUE;
        _M06310 := TRUE; (* 코어 제품차단 SOL *)
        TON_T0629(IN := _M06002 AND _M06209, PT := T#2000ms);
        IF TON_T0629.Q THEN
            _D00620 := 10;
        END_IF;

    10: (* 래더 Line 371 - 스텝10: 자재확인, T#200ms *)
        TON_T0630(IN := _M06002 AND _M0620A, PT := T#2000ms);
        IF TON_T0630.Q THEN
            _D00620 := 11;
        END_IF;
        (* _M01116 AND _M01106: 자재없음 처리 *)

    11: (* 래더 Line 382 - 스텝11: _M06321 ON, T#200ms *)
        _M06321 := TRUE;
        TON_T0631(IN := _M06002 AND _M0620B, PT := T#2000ms);
        IF TON_T0631.Q THEN
            _D00620 := 12;
