    12: (* 래더 Line 392 - 스텝12: 코어 하부(_M0631D) ON, T#200ms *)
        _M0631D := TRUE; (* 코어 하부 상승/하강 SOL *)
        TON_T0632(IN := _M06002 AND _M0620C, PT := T#2000ms);
