    16: (* 래더 Line 433 - 스텝16: 코어 2차이송 후진(_M06314) ON, T#200ms *)
        _M06314 := TRUE; (* 코어 2차이송 후진 SOL *)
        TON_T0636(IN := _M06002 AND _M06210, PT := T#2000ms);
        IF TON_T0636.Q THEN
            _D00620 := 17;
