    17: (* 래더 Line 443 - 스텝17: 코어 1차이송(_M06312) ON, T#200ms *)
        _M06312 := TRUE; (* 코어 1차이송 전진/후진 SOL *)
        TON_T0637(IN := _M06002 AND _M06211, PT := T#2000ms);
        IF TON_T0637.Q THEN
            _D00620 := 18;
        END_IF;

    18: (* 래더 Line 453 - 스텝18: 코어 높이검사보조(_M0631B)+상승/하강(_M06316) ON, T#200ms *)
        _M0631B := TRUE; (* 코어 높이검사 보조 SOL *)
