    19: (* 래더 Line 464 - 스텝19: 특수플래그 시 클램프+작업완료, T#200ms *)
        TON_T0639(IN := _M06002 AND _M06213, PT := T#2000ms);
        IF TON_T0639.Q THEN
            _D00620 := 20;
        END_IF;
        (* _M06251(특수플래그) 조건 처리 *)
        IF _M06251 THEN
            _M0631A := TRUE; (* 코어 2차이송 클램프 SOL *)
